"use client";
import { useEffect, useState } from "react";
import Link from "next/link";
import { getBoardList } from "@/utils/boardApi";
import { useSearchParams, useRouter } from "next/navigation";
import "./board.css"; 

export default function BoardListPage() {
  const searchParams = useSearchParams();
  const router = useRouter();
  const page = parseInt(searchParams.get("page") || "0");
  const [data, setData] = useState<any>(null);

  useEffect(() => {
    getBoardList(page).then(setData);
  }, [page]);

  if (!data) return <div className="board-container" style={{textAlign:'center'}}>데이터를 불러오는 중...</div>;

  return (
    <div className="board-container">
      <div className="board-header">
        <div>
          <h1 className="board-title">자유게시판</h1>
          <p style={{color: '#666', marginTop: '8px'}}>다양한 이야기를 자유롭게 나누어 보세요.</p>
        </div>
        <Link href="/board/write">
          <button className="btn-write">새 글 작성</button>
        </Link>
      </div>

      <div className="board-list-wrapper">
        {data.content.length > 0 ? (
          data.content.map((post: any) => (
            <Link href={`/board/${post.id}`} key={post.id} className="list-item">
              <div className="item-id">{post.id}</div>
              <div className="item-content-wrap">
                <span className="item-title">{post.title}</span>
                <div className="item-info-row">
                  <span className="item-author">{post.userNickname}</span>
                  <span className="item-date">{new Date(post.createdAt).toLocaleDateString()}</span>
                  <div className="item-stats">
                    <span>조회 {post.viewCount}</span>
                    {/* 댓글 수도 API에서 받아온다면 여기에 추가 가능 */}
                  </div>
                </div>
              </div>
            </Link>
          ))
        ) : (
          <div style={{padding: '100px 0', textAlign: 'center', color: '#999'}}>
            등록된 게시글이 없습니다.
          </div>
        )}
      </div>

      <div className="pagination">
        <button 
          className="page-link" 
          disabled={data.first} 
          onClick={() => router.push(`/board?page=${page - 1}`)}
        >
          이전
        </button>
        <span className="page-count">
          <strong>{page + 1}</strong> / {data.totalPages || 1}
        </span>
        <button 
          className="page-link" 
          disabled={data.last} 
          onClick={() => router.push(`/board?page=${page + 1}`)}
        >
          다음
        </button>
      </div>
    </div>
  );
}